-- Lessons
INSERT IGNORE INTO lessons (title, description, xp_reward, lesson_number, required_level, difficulty, content, video_url, created_at, updated_at) VALUES

('Intro to the Guitar',
'Learn how to hold the guitar, tune your strings, and understand the basics of the instrument.',
100, 1, 1, 'BEGINNER',
'[
  {
    "heading": "Your First Moments With the Instrument",
    "text": "Before you play a single note, how you hold the guitar matters more than most beginners realize. Bad posture and tension in your hands are the number one cause of slow progress and even injury. Sit up straight with both feet flat on the floor. Rest the body of the guitar on your strumming-side thigh, and let your strumming arm drape naturally over the top of the body. The neck should angle slightly upward — not pointing at the floor — so your fretting hand can move freely without your wrist bending at an awkward angle. Keep your shoulders relaxed. Tension travels from your shoulders down into your hands, and tense hands cannot play well."
  },
  {
    "heading": "How to Hold a Pick",
    "text": "Pinch the pick between the flat of your thumb and the side of your index finger. The tip of the pick should stick out just a few millimeters — enough to catch the strings but not so much that it wobbles. Hold it firmly enough that it does not fly away, but loosely enough that if someone tried to pull it from your hand, they could. That balance is the sweet spot. A pick held too tightly creates a stiff, clicky sound and tires your hand out quickly. A relaxed grip produces a warmer, more fluid tone and allows you to strum for much longer without fatigue."
  },
  {
    "heading": "The Six Strings and Why They Matter",
    "text": "The guitar has six strings, and every scale, chord, and riff you will ever learn is built on knowing which string is which. From lowest in pitch to highest, the strings are tuned to E, A, D, G, B, and e. The lowest string — the thick one closest to the ceiling when you hold the guitar — is the 6th string, low E. The thinnest string closest to the floor is the 1st string, high e. Guitar teachers commonly use the phrase Every Adult Dog Grows Beyond Expectations to help students memorize this order. Spend a few minutes today just plucking each string individually and saying its name out loud. This sounds simple, but it is genuinely one of the most important things you can do as a beginner."
  },
  {
    "heading": "Fretting Your First Notes",
    "text": "When you press a string against the fretboard, your finger should land just behind the metal fret wire — not on top of it, and not in the middle of the space between two frets. Placing your finger right behind the fret requires the least amount of pressure and produces the clearest, cleanest sound. If you hear a buzzing or muffled noise, your finger is either too far back in the fret space or accidentally touching an adjacent string. Curve your fingers so only the tips make contact, like you are holding a small ball in your fretting hand. This curved, arched finger position is something every great guitarist uses, and building it as a habit from day one will save you months of relearning later."
  },
  {
    "heading": "Where to Go From Here",
    "text": "Your goal for the next few days is simple: get comfortable. Pick up the guitar every day, even if only for ten minutes. Practice holding it correctly, plucking each string by name, and pressing single notes cleanly at various frets. Do not rush to chords yet. The best guitar teachers in the world — Justin Sandercoe of JustinGuitar, Jared Borkowski, and instructors at the London Guitar Institute — all agree that students who rush past fundamentals spend years unlearning bad habits. Treat these early lessons as building the foundation of a house. Everything you will ever play on the guitar rests on what you are learning right now."
  },
  {
    "heading": "Helpful Intro to Guitar Video",
    "videoUrl": "https://www.youtube.com/embed/BBz-Jyr23M4"
  }
]',
'https://www.youtube.com/embed/BBz-Jyr23M4',
NOW(), NOW()),

('Fretboard Navigation for Beginners',
'Learn how the guitar neck is organized so you can find notes and move confidently beyond memorizing shapes.',
100, 2, 1, 'BEGINNER',
'[
  {
    "heading": "Why Most Guitarists Stay Lost on the Fretboard",
    "text": "The majority of guitarists learn shapes — chord shapes, scale shapes, riff shapes — without ever learning what notes those shapes contain. This is like learning to drive using only landmarks without ever understanding street names. You can get around, but the moment something changes, you are lost. Understanding the fretboard at a note level is what separates guitarists who play songs from guitarists who make music. It is what allows you to improvise anywhere on the neck, transpose a song to a different key in seconds, and communicate with other musicians using a shared language."
  },
  {
    "heading": "The Musical Alphabet and How It Works on Guitar",
    "text": "Western music uses twelve notes before the pattern repeats. The natural notes — the ones without sharps or flats — spell out A, B, C, D, E, F, G, and then the alphabet starts again. Between most of these natural notes is a sharp or flat note: A, A#, B, C, C#, D, D#, E, F, F#, G, G#, and then back to A. Notice that there is no sharp between B and C, and no sharp between E and F. Those are the only two places in music where two natural notes sit just one fret apart. Every fret on the guitar is one half-step, and twelve half-steps bring you back to the same note, one octave higher. This means that whatever note is on the open string, the exact same note will appear again at the 12th fret."
  },
  {
    "heading": "Start With the Low E and A Strings",
    "text": "You do not need to memorize every note on every string at once. The most efficient approach — the one used in professional guitar education programs — is to start with just the low E and A strings. These two strings are the root of almost every chord shape and scale position you will ever use. On the low E string, the most important landmarks are the 3rd fret G, the 5th fret A, the 7th fret B, the 8th fret C, the 10th fret D, and the 12th fret E. On the A string, the same formula applies but starting from A. Once you know these two strings fluently, you can derive the notes on the other strings because the guitar is built on repeating interval relationships."
  },
  {
    "heading": "A Practice Method That Actually Works",
    "text": "Do not try to memorize the fretboard through flashcard drilling alone. The most effective approach is active recognition — pick a random fret on the low E string, say the note name before you play it, then verify by counting up from the open string. Do this for five minutes a day and within two weeks you will know the low E string cold. The reason this works better than passive memorization is the same reason medical students learn anatomy by doing procedures, not just reading textbooks. Your brain builds stronger neural pathways when knowledge is retrieved under mild pressure rather than simply reviewed."
  },
  {
    "heading": "Helpful Video for Fretboard Basics",
    "videoUrl": "https://www.youtube.com/embed/kNgpKxHo0H4"
  }
]',
'https://www.youtube.com/embed/kNgpKxHo0H4',
NOW(), NOW()),

('Reading Guitar Tablature',
'Learn how to read tabs so you can learn songs, riffs, and solos from any source online.',
100, 3, 1, 'BEGINNER',
'[
  {
    "heading": "What Tablature Is and Why It Exists",
    "text": "Guitar tablature — tab for short — is a notation system invented specifically for fretted instruments. Unlike standard musical notation, which represents pitch as notes on a staff and requires years of training to read fluently, tab represents physical finger positions on the guitar. It is fast, visual, and intuitive for guitarists. Tab is the reason you can look up almost any song ever recorded and find instructions for how to play it within minutes. It is one of the most powerful self-teaching tools in existence, and learning to read it fluently is one of the best investments a beginner can make."
  },
  {
    "heading": "How to Read the Grid",
    "text": "Tab is displayed as six horizontal lines, each representing a string on the guitar. The bottom line represents the thickest, lowest-pitched string — the low E. The top line represents the thinnest, highest-pitched string — the high e. This is the opposite of how the strings appear when you look down at the guitar while playing, which trips up many beginners. Numbers written on the lines tell you which fret to press. A zero means play the string open without pressing any frets. A 5 on the second line from the bottom means press the 5th fret on the A string. When numbers appear stacked directly on top of each other, press all of those frets simultaneously and strum — that is a chord."
  },
  {
    "heading": "Common Symbols and What They Mean",
    "text": "Beyond basic fret numbers, tab uses a set of symbols to describe guitar techniques. The letter h between two numbers means hammer-on — play the first note, then drive a fretting finger down onto the second note without picking again. The letter p means pull-off — fret both notes simultaneously, play the higher one, then snap your finger off to sound the lower note. The letter b followed by a number means bend — push or pull the string sideways until the pitch rises to match the target note. A forward slash means slide up to the next note, and a backslash means slide down. These techniques are at the heart of expressive guitar playing and mastering them is what makes your playing sound like music rather than a sequence of disconnected notes."
  },
  {
    "heading": "The One Thing Tab Cannot Tell You",
    "text": "Tab has one significant limitation: it does not reliably show rhythm. The spacing between numbers in most tab notation does not represent timing the way note duration does in standard notation. This means you must already know how a song sounds — or listen to it while reading the tab — to understand when to play each note and for how long. This is actually a feature disguised as a limitation. Learning to connect your ears to the notation forces you to develop musical listening skills that will serve you for your entire guitar career. Always listen to the original song before trying to learn it from tab, and let your ears guide your hands."
  }
]',
NULL,
NOW(), NOW()),

('Intro to Strumming and Rhythm',
'Learn how rhythm, timing, and basic strumming patterns shape the groove of your playing.',
100, 4, 1, 'BEGINNER',
'[
  {
    "heading": "Rhythm Is the Foundation, Not the Afterthought",
    "text": "Most beginners focus almost entirely on the notes and chords they are playing and treat rhythm as something that will sort itself out naturally. It does not. Rhythm is the foundation of all music, and the guitar is fundamentally a rhythmic instrument as much as it is a melodic one. A guitarist who plays the right chords with bad rhythm sounds worse than a guitarist who plays simple chords with great rhythm. The legendary session musicians who have played on thousands of hit records — the guitarists you have never heard of but whose playing you know — built their entire careers on one thing: they could be trusted to play in time, every time."
  },
  {
    "heading": "How Your Strumming Hand Should Move",
    "text": "The strumming motion originates from the rotation of your forearm, not from your wrist alone and certainly not from your shoulder. Imagine your forearm as a pendulum swinging from the elbow. Your wrist adds a small, loose, whipping motion at the end of each stroke — this is what gives strumming its natural feel. The single biggest mistake beginners make is locking their wrist and strumming with a stiff arm. This produces a harsh, mechanical sound and causes the forearm to fatigue quickly. Keep everything loose. The pick should glide across the strings like it is brushing through them, not hacking at them."
  },
  {
    "heading": "Understanding Downstrokes and Upstrokes",
    "text": "A downstroke — moving the pick downward toward the floor — naturally emphasizes the lower strings and produces a heavier, more grounded sound. An upstroke — moving the pick upward toward the ceiling — catches the higher strings more prominently and has a lighter, airier quality. In most strumming patterns, downstrokes land on the strong beats (1, 2, 3, 4) and upstrokes fill in the spaces between them (the ands). The critical technique insight that most beginners miss is this: your strumming hand should keep moving in a steady down-up pendulum motion even when you choose not to hit the strings. A strum you skip is still a motion — your hand just passes through the air instead of the strings. This is how you maintain consistent timing even in patterns with gaps."
  },
  {
    "heading": "Your First Real Strumming Pattern",
    "text": "The pattern D - D U - U D U (counted as 1 - 2 and - and 4 and) is one of the most widely used strumming patterns in popular music. The dashes represent beats where your hand moves but skips the strings. To learn it, start by just doing straight down strums on every beat — 1, 2, 3, 4 — until that is absolutely solid. Then add the upstroke on the and of 2. Then the upstroke on the and of 3. Build the pattern one element at a time rather than trying to learn it all at once. Practice it with a metronome at 60 BPM before you ever try it with a chord change. The chord change is easy — the rhythm is the skill."
  },
  {
    "heading": "Helpful Video for Strumming",
    "videoUrl": "https://www.youtube.com/embed/ely9LaJJJr4"
  }
]',
'https://www.youtube.com/embed/ely9LaJJJr4',
NOW(), NOW()),

('Mastering the 8 Essential Beginner Chords',
'Learn the foundational chords every guitarist needs to start playing real songs instantly.',
100, 5, 1, 'BEGINNER',
'[
  {
    "heading": "Why These Eight Chords Unlock Everything",
    "text": "Eight open chords — E major, A major, D major, G major, C major, E minor, A minor, and D minor — appear in thousands of songs across every genre of popular music. Learning to switch between them smoothly is the single milestone that separates someone who is learning guitar from someone who plays guitar. These chords are called open chords because they include open strings that ring freely, giving them a full, resonant sound that is characteristic of acoustic playing. They are also the easiest versions of each chord to finger, making them the ideal starting point for building the left-hand strength and dexterity you will need for everything that follows."
  },
  {
    "heading": "The Physics of a Clean Chord",
    "text": "Every string in a chord must ring clearly for the chord to sound right. This requires two things: your fingertips must press firmly enough to fully contact the string, and they must not accidentally touch adjacent strings. The secret to both is finger curvature. Arch your fretting fingers so that only the very tips press down on the strings, like a spider standing on its legs. Flat fingers are the enemy of clean chords — they mute neighboring strings and require far more pressure to produce a clear note. Place your fingers as close to the fret wire as possible without sitting on top of it. The closer to the fret, the less pressure required and the cleaner the sound."
  },
  {
    "heading": "How to Build Chord Switching Speed",
    "text": "The most effective way to develop smooth chord transitions is a technique called the one-minute change, pioneered by Justin Sandercoe at JustinGuitar. Set a timer for one minute and switch between just two chords — back and forth, as many times as possible — counting each complete change. Write down your score. Do this every practice session. Most beginners start at 20 to 30 changes per minute and reach 60 within a few weeks. The mental focus required to count and improve pushes your brain to optimize the movement faster than mindless repetition would. Once a pair of chords reaches 60 changes per minute, they are ready for use in real songs."
  },
  {
    "heading": "The Chord Pairs to Practice First",
    "text": "Not all chord transitions are created equal. Some are naturally smooth because the finger movement is minimal, while others require large repositioning that takes longer to master. The easiest and most musically useful pairs to start with are E minor to D major, G major to C major, A minor to C major, and D major to A major. The G to C transition deserves special attention because it appears in an enormous number of songs and the finger movement is large enough to challenge most beginners. The Em to D pair is ideal for absolute beginners because Em requires only two fingers and D is a natural next step. Begin with the easiest pair and only add new ones when the current pair is genuinely smooth."
  },
  {
    "heading": "Helpful Video for the Chords",
    "videoUrl": "https://www.youtube.com/embed/lRJ_d3PqPIQ"
  }
]',
'https://www.youtube.com/embed/lRJ_d3PqPIQ',
NOW(), NOW()),

('Power Chords 101',
'Learn how to play power chords — the backbone of rock, punk, metal, and modern guitar playing.',
150, 6, 2, 'BEGINNER',
'[
  {
    "heading": "What Makes a Power Chord So Powerful",
    "text": "A power chord is technically not a full chord — it contains only two distinct pitches, the root note and the perfect fifth. Because it omits the third (the interval that determines whether a chord sounds major or happy versus minor or sad), a power chord has no strong emotional color of its own. Instead, it is harmonically neutral and incredibly versatile. This neutrality is exactly why power chords became the defining sound of rock and punk music. When played through a distorted amplifier, full chords with their thirds create a muddy, dissonant mess. Power chords, with their simpler two-note structure, cut through distortion cleanly and punch with raw authority. Every great rock riff you have ever heard — from Black Sabbath to Green Day — is built on this principle."
  },
  {
    "heading": "The Shape and How to Play It",
    "text": "The most common power chord shape uses three strings. Place your first finger on the root note on either the 6th or 5th string. Your third finger goes one string lower (toward the floor) and two frets higher — this is the perfect fifth. Your fourth finger optionally sits one fret above the third finger on the same string, doubling the root an octave up and adding thickness to the sound. The shape looks identical whether you root it on the 6th or 5th string, which is the beauty of it — learn the shape once and you can play any power chord in any key by simply moving up or down the neck. A power chord rooted on the 6th string at the 5th fret is an A5. Move to the 7th fret and it becomes a B5."
  },
  {
    "heading": "String Muting — The Technique Nobody Talks About",
    "text": "Playing power chords cleanly requires intentional string muting. If you root your power chord on the 6th string, the 1st, 2nd, and 3rd strings must not ring. To prevent them from sounding, lightly rest the underside of your third and fourth fingers across those higher strings without pressing them down — just enough contact to dampen them. On the 5th string, the 6th string above it must be muted, which you accomplish by letting the tip of your first finger lightly touch it. This muting technique is invisible when done correctly but audible in its absence. A cleanly muted power chord sounds precise and aggressive. An unmuted one sounds messy and out of control."
  },
  {
    "heading": "Palm Muting and the Rhythmic Possibilities",
    "text": "One of the most expressive techniques in rock guitar is palm muting — resting the edge of your strumming palm lightly on the strings right at the bridge while you pick. This dampens the sustain and produces the chunky, percussive chugging sound heard in countless rock and metal riffs. The key is placement: too far from the bridge and the strings are fully muted and produce almost no pitch. Too close and there is no muting effect at all. The sweet spot is right at the point where the strings meet the bridge saddles, and it requires some experimentation to find it on your specific guitar. Alternating between palm-muted and open power chords within the same riff creates a dynamic push-pull that is one of the most satisfying textures in all of rock music."
  },
  {
    "heading": "Helpful Video for Power Chords",
    "videoUrl": "https://www.youtube.com/embed/DVveuwoVmmY"
  }
]',
'https://www.youtube.com/embed/DVveuwoVmmY',
NOW(), NOW()),

('Intro to Scales',
'Explore what scales are, why they matter, and how to start using them in your playing.',
150, 7, 2, 'BEGINNER',
'[
  {
    "heading": "What a Scale Actually Is",
    "text": "A scale is a selected group of notes organized in a specific order of intervals — the distances between the notes. That interval pattern is what gives each type of scale its distinctive emotional character. The major scale, built on the pattern whole-whole-half-whole-whole-whole-half, sounds bright, resolved, and familiar because Western ears have been conditioned to it for centuries. The natural minor scale, which lowers the 3rd, 6th, and 7th degrees, sounds darker and more melancholic. The pentatonic scale removes two of the major scale notes and creates something simpler and more universally musical — it is almost impossible to play a wrong note with a pentatonic scale over the right chord. Understanding this relationship between interval patterns and emotional color is the beginning of real musical understanding."
  },
  {
    "heading": "Why the Pentatonic Scale Is Where Every Guitarist Starts",
    "text": "The A minor pentatonic scale in the first box position — rooted at the 5th fret on the low E string — is the first scale taught by virtually every serious guitar education program in the world, from JustinGuitar to Guitar Tricks to Pickup Music. The reason is simple: it sounds great immediately. Play any note in the A minor pentatonic box over an A minor chord and it will work. There are no avoid notes to worry about, no clashing intervals to navigate around. This gives beginners the immediate feedback of sounding musical, which is crucial for maintaining motivation. More importantly, the skills you build learning this one scale — alternate picking, position playing, fretboard awareness — transfer directly to every other scale you will ever learn."
  },
  {
    "heading": "Scales Are Not Exercises — They Are Vocabulary",
    "text": "The most common mistake guitarists make with scales is running them up and down mechanically, treating them like a warm-up exercise. This is technically useful but musically useless. A scale is a vocabulary of notes that work well together. Real musical fluency comes from learning to use individual notes and short phrases within the scale rather than playing the entire pattern from top to bottom. The guitarist who can take two notes from the pentatonic scale and use them expressively — bending, vibrato, varying the rhythm — sounds more musical than the guitarist who can blaze through the entire box at 160 BPM with no feel. Speed and pattern knowledge are the beginning of scale fluency, not the end."
  },
  {
    "heading": "Connecting Scales to Chords and Keys",
    "text": "Every scale has a home key — the note it naturally gravitates toward, called the tonic or root. When you play the A minor pentatonic scale, A is the tonal center and A minor is the chord it fits over most naturally. This is why scale practice sounds most musical when done over a backing track or a chord. Without a harmonic context, you are just playing notes. Over an A minor chord, you are making music. The relationship between scales and the chords they work over is the foundation of improvisation, and understanding even the basics of this relationship will transform the way you think about and hear music."
  },
  {
    "heading": "Helpful Video for Scales",
    "videoUrl": "https://www.youtube.com/embed/fq68vpUftV8"
  }
]',
'https://www.youtube.com/embed/fq68vpUftV8',
NOW(), NOW()),

('Barre Chords Fundamentals',
'Master barre chords to unlock every key on the guitar and play songs that open chords cannot cover.',
200, 8, 3, 'INTERMEDIATE',
'[
  {
    "heading": "What Barre Chords Change About Your Playing",
    "text": "Open chords are tied to specific positions on the neck. You can play G major, C major, and D major in their open positions, but if someone asks you to play G# major or Eb major, you are stuck without barre chords. Barre chords break this limitation completely. By laying your index finger flat across all six strings and forming a chord shape behind it with your remaining fingers, you create a movable chord that can be played in any key simply by shifting its position up or down the neck. A guitarist who knows barre chords has access to every major and minor chord in every key without learning a single new shape — only a new position."
  },
  {
    "heading": "The Index Finger — Your Movable Nut",
    "text": "When you play an open E major chord, the nut of the guitar holds down the strings at the zero fret. Your index finger in a barre chord replaces the nut — it acts as an artificial capo, pressing all six strings at whatever fret you choose. The open chord shape you form with your remaining fingers sits behind it exactly as it would in the open position. This is why the two most important barre chord shapes are based on the E major and A major open chord shapes. If you move an E major shape up two frets with your index finger barring the second fret, you get an F# major. Move it to the fifth fret and you have an A major barre chord. The open shape you already know gives you the framework — the barre gives you the mobility."
  },
  {
    "heading": "The Physical Reality of Barre Chords",
    "text": "Barre chords are genuinely difficult at first and require physical conditioning that takes weeks of consistent practice to develop. Your index finger must press six strings cleanly at a single fret, which demands finger strength and precise placement. The most common problem is buzzing or muffled notes, almost always caused by one of three things: the index finger is not close enough to the fret wire, the thumb is too high on the back of the neck reducing leverage, or the finger is landing on a joint rather than between them. Experiment with rolling your index finger very slightly away from you toward the headstock — the bony edge of your finger is firmer than the fleshy pad and produces a cleaner barre. Start practicing at the 5th fret where the strings are closest to the fretboard and require less pressure, then work your way toward the 1st fret as your strength improves."
  },
  {
    "heading": "Building Toward Fluency",
    "text": "The best way to develop barre chord strength is daily short practice sessions rather than infrequent long ones. Hold the barre chord shape, press down, check each string individually by plucking them one at a time, adjust anything that is buzzing, then release and repeat. Ten minutes of this focused work every day will build the necessary strength and muscle memory faster than an hour of frustrated strumming every few days. The psychological breakthrough most guitarists describe is the moment they stop thinking about the barre and start thinking about the music — the chord becomes automatic. That moment will come, and when it does, the entire fretboard will feel like it just opened up."
  },
  {
    "heading": "Helpful Video for Barre Chords",
    "videoUrl": "https://www.youtube.com/embed/d4PkHDFMCCo"
  }
]',
'https://www.youtube.com/embed/d4PkHDFMCCo',
NOW(), NOW()),

('Basic Music Theory for Guitarists',
'Understand notes, intervals, and how chords are built so you can make sense of what you are playing.',
200, 9, 3, 'INTERMEDIATE',
'[
  {
    "heading": "Why Theory Is a Tool, Not a Rulebook",
    "text": "Music theory has a reputation for being academic, dry, and irrelevant to real playing. This reputation is completely undeserved. Theory is simply the language musicians use to describe what they are hearing and playing. Learning it does not constrain your creativity — it explains what you are already doing intuitively and gives you tools to do it more intentionally. Every guitarist who says they do not need theory already uses it without realizing it. When you choose a minor chord because it sounds sadder, you are applying theory. When you notice that a riff sounds unresolved and needs one more note, you are hearing theory. Learning it consciously just means you can do these things on purpose."
  },
  {
    "heading": "Intervals — The Building Blocks of Everything",
    "text": "An interval is the distance between any two notes, measured in half-steps (frets). Every musical structure — chords, scales, melodies, progressions — is assembled from intervals. The most important intervals to know early are the major third (4 frets), the minor third (3 frets), and the perfect fifth (7 frets). Here is why they matter immediately: a major chord is built from a root, a major third above it, and a perfect fifth above the root. A minor chord uses the same structure but with a minor third instead of a major third. That single change — one fret difference in the middle note — is the entire reason a major chord sounds happy and a minor chord sounds sad. Understanding this is more useful than memorizing a hundred individual chord shapes."
  },
  {
    "heading": "The Major Scale Formula",
    "text": "The major scale is the foundation of Western music theory and the reference point from which virtually everything else is defined. It is built using the interval pattern whole-whole-half-whole-whole-whole-half, where a whole step is two frets and a half step is one fret. Starting from any note and applying this formula gives you the major scale in that key. The C major scale — C D E F G A B C — is the most commonly used example because it contains no sharps or flats. Every mode, every chord in a key, every scale comparison is ultimately defined in relation to the major scale. Learning this formula is the equivalent of learning the alphabet — it is the starting point from which everything else becomes readable."
  },
  {
    "heading": "How Chords Are Built From Scales",
    "text": "Once you have a major scale, you can build a chord on every note of that scale using a process called harmonization. Take every other note of the scale — the 1st, 3rd, and 5th — and stack them together. That is your first chord, built on the root. Do the same starting from the 2nd scale degree: take the 2nd, 4th, and 6th notes. That is your second chord. Continue this process through all seven scale degrees and you get the seven chords that naturally belong to that key. In the key of G major, these are G major, A minor, B minor, C major, D major, E minor, and F# diminished. This is why certain chord combinations sound so natural together — they are all family members of the same key. Understanding this concept transforms random chord memorization into a coherent system."
  }
]',
NULL,
NOW(), NOW()),

('Fingerpicking Fundamentals',
'Learn how to fingerpick so you can add texture, dynamics, and expressiveness to your playing.',
250, 10, 4, 'INTERMEDIATE',
'[
  {
    "heading": "A Different Relationship With the Guitar",
    "text": "Fingerpicking is not just an alternative to using a pick — it is a fundamentally different way of relating to the instrument. With a pick, you produce one note at a time in a strummed or single-note context. With your fingers, you can sound a bass note with your thumb while your fingers play a melody simultaneously, creating the illusion of two guitarists playing at once. This is why fingerstyle guitar is so arresting to listen to. Artists like Tommy Emmanuel, John Mayer, and virtually the entire tradition of folk and classical guitar are built on this principle. Learning even the basics of fingerpicking will expand your musical vocabulary more than almost any other technique at the intermediate level."
  },
  {
    "heading": "The Role of Each Finger",
    "text": "In standard fingerpicking technique, the thumb (p, from the Spanish pulgar) handles the bass strings — the low E, A, and D strings. The index finger (i, from indice) is assigned to the G string. The middle finger (m, from medio) plays the B string. The ring finger (a, from anular) covers the high e string. These assignments are not arbitrary — they create a logical division of the strings that allows the thumb and fingers to operate independently, the way a pianist uses the left hand for bass and the right hand for melody. The pinky (c) is rarely used in standard technique. In the beginning, practice placing your fingers on their assigned strings without playing anything, just to build the physical awareness of where each finger belongs."
  },
  {
    "heading": "Travis Picking — The Foundation of Fingerstyle",
    "text": "Travis picking, named after country legend Merle Travis, is the most widely taught and musically versatile fingerpicking pattern in existence. The thumb alternates steadily between two bass strings — typically the low E and D, or A and D depending on the chord — while the fingers fill in with melody notes on the treble strings in between the thumb beats. The result is a self-accompanying pattern where bass and melody weave together into something that sounds far more complex than it is. The key to learning Travis picking is separating the two hands completely in your practice. Spend dedicated time just alternating the thumb between two strings with no fingers at all until the thumb movement is automatic. Only then add the finger pattern. Trying to learn both simultaneously almost never works."
  },
  {
    "heading": "Tone, Touch, and Dynamics",
    "text": "One of the greatest advantages of fingerpicking over pick playing is the tonal control available to you. Where you pluck the string dramatically changes the sound. Plucking near the bridge produces a bright, defined tone with lots of attack. Moving your hand closer to the soundhole or neck produces a warmer, rounder tone with more sustain. Your nail angle matters too — the combination of flesh and nail as your fingertip crosses the string creates the characteristic fingerstyle tone that gives the technique its warmth. Equally important is dynamics — the ability to play quietly and loudly within a single phrase. Fingerpicking is one of the most dynamic techniques on the guitar, and learning to vary your touch expressively is what will eventually make your playing feel alive rather than mechanical."
  },
  {
    "heading": "Helpful Video for Fingerpicking",
    "videoUrl": "https://www.youtube.com/embed/j4dMnAPZu60"
  }
]',
'https://www.youtube.com/embed/j4dMnAPZu60',
NOW(), NOW());

-- SONGS

INSERT IGNORE INTO songs (title, artist, song_key, release_date, album_cover_url, details, video_url, tab_url, chords_used, scales_used) VALUES
('Landslide', 'Fleetwood Mac', 'Eb', '1975', 'https://coverartarchive.org/release-group/416bb5e5-c7d1-3977-8fd7-7c9daf6c2be6/front', 'Written by Stevie Nicks at a crossroads in her life, Landslide is one of the most emotionally honest songs in the Fleetwood Mac catalog. Lindsey Buckingham''s fingerpicking pattern is deceptively simple yet deeply expressive. Capo 3 is used to achieve the Eb sound while playing open chord shapes, making it accessible for intermediate players.', 'https://www.youtube.com/embed/mXonGAEPQp8?si=F3ZkAAWUh45NwrMt', 'https://www.songsterr.com/a/wsa/fleetwood-mac-landslide-tab-s7537', 'C, G, Am, D', 'C Major (Capo 3)'),

('Nothing Else Matters', 'Metallica', 'Em', '1991', 'https://coverartarchive.org/release-group/3d00fb45-f8ab-3436-a8e1-b4bfc4d66913/front', 'James Hetfield wrote Nothing Else Matters as a love song while on tour, originally never intending to share it with the band. The open string fingerpicking intro is iconic and deceptively approachable, while the full arrangement with orchestra on the Black Album version showcases Metallica''s range beyond their thrash roots.', 'https://www.youtube.com/embed/tAGnKpE4NCI?si=AbR3y93lrEFIbX9k', 'https://www.songsterr.com/a/wsa/metallica-nothing-else-matters-tab-s439171', 'Em, D, C, G, B7, Am', 'E Natural Minor'),

('Built By Nations', 'Greta Van Fleet', 'E', '2021', 'https://coverartarchive.org/release-group/7b2b6b9b-5469-4953-8206-4f2af64db840/front', 'From the album The Battle at Garden''s Gate, Built By Nations is one of Greta Van Fleet''s most ambitious guitar compositions. Jake Kiszka''s riff work draws from classic hard rock while pushing into progressive territory, with dynamic shifts and technical passages that demand serious fretboard command. A challenging but rewarding song for players ready to push their skills.', 'https://www.youtube.com/embed/EsI1ujh65u0?si=tq8QOZ5OhOxLV2aZ', 'https://www.songsterr.com/a/wsa/greta-van-fleet-built-by-nations-tab-s680391', 'E, A, D, B, C#m', 'E Minor Pentatonic / E Major'),

('Wish You Were Here', 'Pink Floyd', 'G', '1975', 'https://upload.wikimedia.org/wikipedia/en/a/a4/Pink_Floyd%2C_Wish_You_Were_Here_%281975%29.png', 'Written as a tribute to founding member Syd Barrett, Wish You Were Here is one of Pink Floyd''s most beloved songs. The iconic fingerpicked intro is one of the first things many guitarists learn, yet mastering its feel and dynamics takes years. David Gilmour''s tone and phrasing on this track are a masterclass in emotional restraint.', 'https://www.youtube.com/embed/IXdNnw99-Ic?si=Zge1aSiTFMLODLrj', 'https://www.songsterr.com/a/wsa/pink-floyd-wish-you-were-here-tab-s153', 'Em, G, A, C, D', 'G Major / E Minor'),

('Pneuma', 'Tool', 'D', '2019', 'https://coverartarchive.org/release-group/76203bd0-466b-4802-a7ca-9b0097a3f862/front', 'The opening track from Tool''s long awaited Fear Inoculum album, Pneuma is a sprawling progressive metal epic that showcases the band''s mastery of odd time signatures and dynamic shifts. Adam Jones''s guitar work weaves between heavy riff-driven passages and hypnotic clean sections, making it one of the most musically complex songs on this list.', 'https://www.youtube.com/embed/5ClCaPmAA7s?si=1uv2-akJwuw6rAPH', 'https://www.songsterr.com/a/wsa/tool-pneuma-tab-s455388', 'Dm, F, C, Bb, G', 'D Minor / D Phrygian'),

('Comfortably Numb', 'Pink Floyd', 'Bm', '1979', 'https://upload.wikimedia.org/wikipedia/en/thumb/a/ab/The_Dark_Side_of_the_Moon_cover.svg/1920px-The_Dark_Side_of_the_Moon_cover.svg.png', 'From the landmark album The Wall, Comfortably Numb features what many consider David Gilmour''s greatest guitar solo. The song is a dialogue between Roger Waters and Gilmour both lyrically and sonically, with the verses cold and distant and the choruses expansive and emotional. The second solo in particular is a lesson in melodic phrasing and sustain.', 'https://www.youtube.com/embed/eHKG7EMxWW8?si=9iA6FzdbQY3__BkW', 'https://www.songsterr.com/a/wsa/pink-floyd-comfortably-numb-tab-s271', 'Bm, A, G, Em, C, D', 'B Minor'),

('Jumper', 'Third Eye Blind', 'G', '1997', 'https://coverartarchive.org/release/bf333fb1-a5c4-413a-a663-43b0c603eab5/5596626641.jpg', 'One of Third Eye Blind''s most emotionally resonant songs, Jumper tackles the subject of suicide with empathy and directness. Written by Stephan Jenkins, the song features a simple but powerful chord progression that made it an instant acoustic staple. It remains one of the most requested songs for campfire settings due to its singalong chorus and approachable chord shapes.', 'https://www.youtube.com/embed/gRYZijLZR-Q?si=ElXP9J2jj7KBFI8b', 'https://www.songsterr.com/a/wsa/third-eye-blind-jumper-tab-s23494', 'G, Cadd9, D, Em', 'G Major'),

('House of the Rising Sun', 'The Animals', 'Am', '1964', 'https://coverartarchive.org/release/afa79809-0393-4e48-bf4d-5eade3b6b3d0/1573887394.jpg', 'A traditional American folk song adapted by The Animals, featuring one of the most recognizable arpeggiated fingerpicking patterns in rock history. Eric Burdon''s haunting vocals combined with Alan Price''s organ create an atmosphere of despair and regret. The song reached number one on both sides of the Atlantic and became a defining moment of the British Invasion.', 'https://www.youtube.com/embed/N4bFqW_eu2I?si=wWz3-Yx31LjJaplE', 'https://www.songsterr.com/a/wsa/animals-the-house-of-the-rising-sun-tab-s63', 'Am, C, D, F, E', 'A Natural Minor'),

('Knockin'' on Heaven''s Door', 'Bob Dylan', 'G', '1973', 'https://coverartarchive.org/release/5b3ec538-cbe7-4f5c-8a79-4d3b1a550295/17167259693.jpg', 'Written for the soundtrack of Pat Garrett and Billy the Kid, this Dylan classic is one of the most covered songs in history. Its sparse, hymn-like quality and simple chord progression make it an ideal song for beginners while its emotional weight gives experienced players plenty to explore in terms of feel and phrasing.', 'https://www.youtube.com/embed/rm9coqlk8fY?si=b7CuijKyVoMZIsEX', 'https://www.songsterr.com/a/wsa/bob-dylan-knockin-on-heavens-door-tab-s69238', 'G, D, Am, C', 'G Major'),

('Blackbird', 'The Beatles', 'G', '1968', 'https://coverartarchive.org/release-group/9162580e-5df4-32de-80cc-f45a8d8a9b1d/front', 'Paul McCartney wrote Blackbird as an allegory for the Civil Rights Movement in America. Recorded as a solo acoustic piece on a Martin D-28, the song is a masterclass in fingerpicking technique. The alternating bass note pattern combined with the melody played simultaneously makes this a true benchmark song for acoustic guitarists.', 'https://www.youtube.com/embed/Man4Xw8Xypo?si=N65zLywndGK4K5xx', 'https://www.songsterr.com/a/wsa/beatles-blackbird-tab-s57', 'G, Am, G/B, C, A7/C#, D, Dm, Em', 'G Major'),

('Nutshell', 'Alice in Chains', 'E', '1994', 'https://coverartarchive.org/release-group/3b6b7688-c97b-3d11-9334-3158468074f7/front', 'From the MTV Unplugged era, Nutshell is widely considered one of Layne Staley''s most vulnerable vocal performances. Jerry Cantrell''s open tuning creates a rich, melancholic texture that perfectly mirrors the lyrical themes of isolation and longing. This song is a touchstone for anyone exploring the emotional depth of acoustic rock.', 'https://www.youtube.com/embed/G23iLGhh9lo?si=LTde7O8PbT0Jdx4o', 'https://www.songsterr.com/a/wsa/alice-in-chains-nutshell-tab-s23793', 'Em, G, D, A, C', 'E Minor'),

('Stairway to Heaven', 'Led Zeppelin', 'Am', '1971', 'https://coverartarchive.org/release-group/2e61da88-39e9-3473-81d2-c964cb394952/front', 'Widely regarded as one of the greatest rock songs ever written, Stairway to Heaven is a journey through multiple musical movements. Jimmy Page''s fingerpicked intro using a Harmony Sovereign acoustic is one of the most studied passages in guitar history. The song builds from delicate arpeggios to a full electric climax featuring one of rock''s most celebrated guitar solos.', 'https://www.youtube.com/embed/QkF3oxziUI4?si=CmaOgqGiaMhmm7vQ', 'https://www.songsterr.com/a/wsa/led-zeppelin-stairway-to-heaven-tab-s27', 'Am, G, F, C, D, Em', 'A Minor / A Major'),

('Hey Joe', 'Jimi Hendrix', 'E', '1966', 'https://coverartarchive.org/release-group/da40e720-2097-3730-8a7f-0c2ddbff4a96/front', 'Although written by Billy Roberts, Hey Joe became Jimi Hendrix''s debut single and one of his most iconic performances. The descending chord progression is deceptively simple but Hendrix''s interpretation — combining rhythm, lead, and bass lines simultaneously — reveals layers of complexity. His tone, vibrato, and phrasing set a standard that guitarists have chased for decades.', 'https://www.youtube.com/embed/rXwMrBb2x1Q?si=4_CkzYYD_AYBthnx', 'https://www.songsterr.com/a/wsa/jimi-hendrix-hey-joe-tab-s22556', 'C, G, D, A, E', 'E Major / Blues'),

('Babe I''m Gonna Leave You', 'Led Zeppelin', 'Am', '1969', 'https://coverartarchive.org/release-group/0f18ec88-aa87-38a9-8a65-f03d81763560/front', 'Originally a folk song by Anne Bredon, Led Zeppelin''s interpretation transforms it into a dynamic showcase of contrast — delicate fingerpicked acoustic passages exploding into powerful electric sections. Jimmy Page''s acoustic work here is some of his finest, demonstrating how classical fingerpicking technique can coexist with raw rock energy.', 'https://www.youtube.com/embed/zX_wwlIZ6ko?si=_rUEEUWgCNe76B1C', 'https://www.songsterr.com/a/wsa/led-zeppelin-babe-im-gonna-leave-you-live-1969-tab-s89646', 'Am, Am7, C, D, F, E', 'A Minor'),

('Fade to Black', 'Metallica', 'Bm', '1984', 'https://coverartarchive.org/release-group/67553e23-8dad-3792-b6f2-8fedd5650ff3/front', 'Metallica''s first ballad and one of their most emotionally charged compositions, Fade to Black was groundbreaking for a thrash metal band in 1984. The song moves from a clean fingerpicked intro through increasingly heavy sections before culminating in an extended guitar solo showcase from Kirk Hammett. It remains one of the most studied songs for players transitioning from acoustic to electric.', 'https://www.youtube.com/embed/WEQnzs8wl6E?si=yGQw49vlX27LIq39', 'https://www.songsterr.com/a/wsa/metallica-fade-to-black-acoustic-tab-s549617', 'Bm, E, A, G, F#m', 'B Minor'),

('Age of Machine', 'Greta Van Fleet', 'Dm', '2020', 'https://coverartarchive.org/release-group/7b2b6b9b-5469-4953-8206-4f2af64db840/front', 'From the album The Battle at Garden''s Gate, Age of Machine showcases Greta Van Fleet''s continued evolution as a band. Jake Kiszka''s guitar work blends melodic sensibility with raw power, featuring driving riff sections and expressive lead passages. The song is a testament to the band''s commitment to keeping classic rock alive while pushing it forward.', 'https://www.youtube.com/embed/b-Ex-k_gVSk?si=4welPr7x88Awp3ko', 'https://www.songsterr.com/a/wsa/greta-van-fleet-age-of-machine-tab-s595519', 'Dm, C, F, G', 'D Minor');